import { InfoOutlined } from '@mui/icons-material';
import {
  Box,
  Button,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Stack,
  Typography,
} from '@mui/material';
import _ from 'lodash';
import { FC } from 'react';

import { AppRoleChip } from '@/components/app-role/app-role-chip';
import useServicesHook from '@/hooks';
import { User } from '@/models/user';
import { translate, TranslationKey } from '@/utils/i18n';

import { CommonModal } from '../common-modal';

export type DeactivateUserRoleModalParam = {
  teamId: string;
  user: User | null;
  onClose: Function;
  onSuccess: Function;
  onFailed: Function;
};

export const DeactivateUserRoleModal: FC<DeactivateUserRoleModalParam> = ({
  teamId,
  user,
  onClose,
  onSuccess,
  onFailed,
}) => {
  const { services } = useServicesHook();

  const deactivateUserRole = async (): Promise<void> => {
    if (_.isNil(user)) {
      return;
    }

    const { error } = await services.default.user.deactivateUserRole(
      teamId,
      user.id,
    );
    onClose();

    if (error) {
      onFailed();
      return;
    }

    onSuccess();
  };

  if (_.isNil(user)) {
    return <></>;
  }

  return (
    <CommonModal
      isOpen={true}
      onClose={onClose}
      setIsOpen={(b) => {
        onClose();
      }}
    >
      <Typography variant="h4">{translate('remove_member')}</Typography>
      <Typography sx={{ mb: 2 }}>
        {translate('are_you_sure_you_want_to_deactivate_this_member')}
      </Typography>

      <Stack direction="column" spacing={2} sx={{ mt: 1 }} alignItems="center">
        <Box>{user.profile.username}</Box>
        {_.map(user.givenUserRoles[teamId], (userRole) => {
          return (
            <AppRoleChip key={userRole.id} roleGroup={userRole.roleGroup} />
          );
        })}

        <List dense>
          {(
            [
              'deactivate_member_description_1',
              'deactivate_member_description_2',
              'deactivate_member_description_3',
            ] as TranslationKey[]
          ).map((translationKey) => (
            <ListItem key={translationKey}>
              <ListItemIcon sx={{ minWidth: 32, pt: 0.25 }}>
                <InfoOutlined />
              </ListItemIcon>
              <ListItemText primary={translate(translationKey)} />
            </ListItem>
          ))}
        </List>

        <Stack direction="column" width="100%">
          <Button
            color="error"
            sx={{ mt: 2, mb: 1 }}
            variant="contained"
            onClick={deactivateUserRole}
          >
            {translate('button_remove')}
          </Button>
          <Button
            color="neutral"
            sx={{ mb: 1 }}
            onClick={() => {
              onClose();
            }}
          >
            {translate('button_cancel')}
          </Button>
        </Stack>
      </Stack>
    </CommonModal>
  );
};

