): InviteUserModalParam => {
  return {
    isEditing: false,
    username: '',
    email: '',
    appRole: EMPTY_APP_ROLE,
    team,
  };
};

export const InviteUserModal: FC<{
  param: InviteUserModalParam;
  setParam: Dispatch<SetStateAction<InviteUserModalParam>>;
  onSuccess: Function;
}> = ({ param, setParam, onSuccess }) => {
  const { services } = useServicesHook();
  const [error, setError] = useState<ServiceError | null>(null);
  const currentUser = useSelector((state) => state.user.me);

  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);

  const availableRoles = useMemo(() => {
    const map: { [role: string]: { name: string; description: string } } = {};
    for (const role of ['team_member', 'team_manager', 'team_admin']) {
      map[role] = {
        name: userRoleToDispName(role),
        description: userRoleToDescription(role),
      };
    }
    return map;
  }, []);

  const resetData = () => {
    setParam({
      ...inviteUserModalParamDefault(param.team),
    });
    setError(null);
  };

  const inviteUser = async () => {
    const team = param.team;
    if (param.appRole === EMPTY_APP_ROLE || !currentUser || !team) {
      return;
    }
    setError(null);

    const role = param.appRole;

    wrapForLoading(setIsSubmitting, async () => {
      const { error } = await services.default.user.inviteUser(team.id, {
        email: param.email,
        role: role,
        userName: param.username,
      });

      if (error) {
        setError(error);
        return;
      }

      // Close this modal.
      setParam(inviteUserModalParamDefault(param.team));
      onSuccess();
    });
  };

  useEffect(() => {
    if (param.isEditing) {
      setError(null); // this might not be necessary
    }
  }, [param]);

  return (
    <CommonModal
      isOpen={param.isEditing}
      onClose={resetData}
      setIsOpen={resetData}
    >
      <Typography variant="h4">{translate('invite_new_member')}</Typography>
      <Stack direction="column" spacing={2} sx={{ pt: 2 }} alignItems="center">
        <Box width="100%">
          <TextField
            fullWidth
            type={'text'}
            label={translate('name')}
            value={param.username}
            onChange={(e) => {
              setParam({
                ...param,
                username: e.target.value,
              });
            }}
          />
          <ValidationError
            error={error}
            pos={['userName']}
            sx={{ ml: 1, mt: 1 }}
          />
        </Box>
        <Box width="100%">
          <TextField
            fullWidth
            type={'email'}
            label={translate('email')}
            value={param.email}
            onChange={(e) => {
              setParam({
                ...param,
                email: e.target.value,
              });
            }}
          />
          <ValidationError
            error={error}
            pos={['email']}
            sx={{ ml: 1, mt: 1 }}
          />
        </Box>

        <Select
          fullWidth
          value={param.appRole}
          renderValue={(appRole) =>
            availableRoles[appRole]?.name ?? translate('empty_role')
          }
          onChange={(e) => {
            if (_.has(availableRoles, e.target.value)) {
              setParam({
                ...param,
                appRole: e.target.value as AppRoles,
              });
            }
          }}
        >
          <MenuItem value={EMPTY_APP_ROLE}>{translate('empty_role')}</MenuItem>
          {_.map(availableRoles, (info, role) => (
            <MenuItem key={role} value={role}>
              <Box>
                <Typography fontWeight="medium">{info.name}</Typography>
                <Typography>{info.description}</Typography>
              </Box>
            </MenuItem>
          ))}
        </Select>

        <CriticalError error={error} />

        <Button
          color="primary"
          disabled={param.appRole === EMPTY_APP_ROLE}
          fullWidth
          loading={isSubmitting}
          variant="contained"
          onClick={async () => {
            await inviteUser();
          }}
        >
          {translate('button_invite')}
        </Button>

        <Button
          color="neutral"
          fullWidth
          onClick={() => {
            setParam({
              ...inviteUserModalParamDefault(param.team),
            });
          }}
        >
          {translate('button_cancel')}
        </Button>
      </Stack>
    </CommonModal>
  );
};

