import { AppRoles } from '@/models/types';
import { translate } from '@/utils/i18n';

export type UserRoleData = {
  isSuperAdmin: boolean;
  isTeamAdmin: boolean;
  isTeamManager: boolean;
  isTeamMember: boolean;
  isPersonalUser: boolean;
};

export const UserRoleDataDefault: UserRoleData = {
  isSuperAdmin: false,
  isTeamAdmin: false,
  isTeamManager: false,
  isTeamMember: false,
  isPersonalUser: false,
};

export const userRoleToDispName = (role: string | null | undefined): string => {
  switch (role) {
    case 'super_admin':
    case 'super_reader':
    case 'team_admin':
    case 'team_manager':
    case 'team_member':
    case 'personal_user':
      return translate(role);
    default:
      return role ?? '-';
  }
};

export const userRoleToDescription = (
  role: string | null | undefined,
): string => {
  switch (role) {
    case 'team_admin':
    case 'team_manager':
    case 'team_member':
      return translate(`${role}_description`);
    default:
      return '';
  }
};

