import {
  Box,
  Button,
  MenuItem,
  Select,
  Stack,
  Typography,
} from '@mui/material';
import _ from 'lodash';
import { FC, useEffect, useMemo, useState } from 'react';

import CriticalError from '@/components/common/critical-error';
import { CommonModal } from '@/components/modal/common-modal';
import useServicesHook from '@/hooks';
import { AppRoles } from '@/models/types';
import { User } from '@/models/user';
import { ServiceError } from '@/services/errors/service-error';
import { translate } from '@/utils/i18n';
import {
  userRoleToDescription,
  userRoleToDispName,
} from '@/utils/user-role-util';

type EditUserRoleModalParam = {
  teamId: string;
  selectedRole: AppRoles | null;
  onDiscard: Function;
  onSave: Function;
  targetUser: User | null;
};

export const EditUserRoleModal: FC<EditUserRoleModalParam> = ({
  teamId,
  selectedRole,
  targetUser,
  onDiscard,
  onSave,
}) => {
  const { services } = useServicesHook();

  const [error, setError] = useState<ServiceError | null>(null);
  const [newAppRole, setNewAppRole] = useState<AppRoles>('team_member');

  const availableRoles = useMemo(() => {
    const map: { [role: string]: { name: string; description: string } } = {};
    for (const role of ['team_member', 'team_manager', 'team_admin']) {
      map[role] = {
        name: userRoleToDispName(role),
        description: userRoleToDescription(role),
      };
    }
    return map;
  }, []);

  // functions
  const updateUserRole = async () => {
    if (!_.isString(targetUser?.id)) {
      return;
    }

    const { error } = await services.default.user.updateUserRole(
      teamId,
      targetUser.id,
      {
        role: newAppRole,
      },
    );
    if (error) {
      setError(error);
      return;
    }

    onSave();
  };

  useEffect(() => {
    if (!_.isNil(selectedRole)) {
      setNewAppRole(selectedRole);
    }
  }, []);

  if (_.isNull(targetUser)) {
    return <></>;
  }

  return (
    <>
      <CommonModal isOpen={true} onClose={onDiscard}>
        <Typography id="modal-modal-title" variant="h4">
          {translate('edit_user_role')}
        </Typography>
        <Typography sx={{ mb: 1 }}>
          {translate('dont_forget_to_save_our_changes')}
        </Typography>
        <Stack direction="row" spacing={1} sx={{ mb: 2, px: 2 }}>
          <Stack direction="column">
            <Typography fontWeight="medium">Name</Typography>
            <Typography fontWeight="medium">Email</Typography>
          </Stack>
          <Stack direction="column">
            <Typography>{targetUser.profile.username}</Typography>
            <Typography>{targetUser.email}</Typography>
          </Stack>
        </Stack>
        <Stack direction="column" spacing={2}>
          <Select
            fullWidth
            sx={{ mb: 4 }}
            value={newAppRole}
            renderValue={(appRole) => availableRoles[appRole]?.name}
            onChange={(e) => {
              if (_.has(availableRoles, e.target.value)) {
                setNewAppRole(e.target.value as AppRoles);
              }
            }}
          >
            {_.map(availableRoles, (info, role) => (
              <MenuItem key={role} value={role}>
                <Box>
                  <Typography fontWeight="medium">{info.name}</Typography>
                  <Typography>{info.description}</Typography>
                </Box>
              </MenuItem>
            ))}
          </Select>
          <CriticalError error={error} />
          <Box>
            <Button
              color="primary"
              fullWidth
              sx={{ mb: 1 }}
              variant="contained"
              onClick={() => {
                updateUserRole();
              }}
            >
              {translate('button_save_changes')}
            </Button>
            <Button
              color="neutral"
              fullWidth
              sx={{ mb: 1 }}
              onClick={() => {
                onDiscard();
              }}
            >
              {translate('button_discard')}
            </Button>
          </Box>
        </Stack>
      </CommonModal>
    </>
  );
};

