import { Box, Button, Stack, Typography } from '@mui/material';
import _ from 'lodash';
import { FC } from 'react';

import useServicesHook from '@/hooks';
import { Profile } from '@/models/profile';
import { translate } from '@/utils/i18n';

import { CommonModal } from '../common-modal';

export type ReactivateUserRoleModalParam = {
  teamId: string;
  profile: Profile | null;
  onClose: Function;
  onSuccess: Function;
  onFailed: Function;
};

export const ReactivateUserRoleModal: FC<ReactivateUserRoleModalParam> = ({
  teamId,
  profile,
  onClose,
  onSuccess,
  onFailed,
}) => {
  const { services } = useServicesHook();

  const reactivateUser = async (): Promise<void> => {
    if (_.isNil(profile)) {
      return;
    }

    const { error } = await services.default.user.activateUserRole(
      teamId,
      profile.id,
    );

    onClose();

    if (error) {
      onFailed();
      return;
    }

    onSuccess();
  };

  if (_.isNil(profile)) {
    return <></>;
  }

  return (
    <CommonModal
      isOpen={true}
      onClose={onClose}
      setIsOpen={(b) => {
        onClose();
      }}
    >
      <Typography variant="h4">{translate('reactivate_member')}</Typography>
      <Typography sx={{ mb: 2 }}>
        {translate('are_you_sure_you_want_to_reactivate_this_member')}
      </Typography>

      <Stack direction="column" spacing={2} sx={{ mt: 1 }} alignItems="center">
        <Box>{profile.username}</Box>

        <Button
          color={'primary'}
          fullWidth
          sx={{ mb: 1 }}
          variant="contained"
          onClick={reactivateUser}
        >
          {translate('button_readd')}
        </Button>

        <Button
          color={'neutral'}
          fullWidth
          sx={{ mb: 1 }}
          onClick={() => {
            onClose();
          }}
        >
          {translate('button_cancel')}
        </Button>
      </Stack>
    </CommonModal>
  );
};
